91	        }
92	        .activity-table tr:last-child td {
93	            border-bottom: none; /* 移除最后一行的底线 */
94	        }
95	        /* 对齐规范：文本靠左，数字靠右 */
96	        .text-left { text-align: left; }
97	        .text-right { text-align: right; }
