177	    { "name": "清晨跑步", "km": 7.67, "pace": "5'54\"", "bpm": 128, "time": "45min", "datetime": "2026-01-08 07:05:05" },
178	    { "name": "清晨跑步", "km": 6.44, "pace": "5'27\"", "bpm": 133, "time": "34min", "datetime": "2026-01-07 06:33:04" },
179	    { "name": "清晨跑步", "km": 11.50, "pace": "5'31\"", "bpm": 134, "time": "63min", "datetime": "2026-01-06 06:55:00" },
180	    { "name": "清晨跑步", "km": 5.11, "pace": "6'18\"", "bpm": 124, "time": "32min", "datetime": "2026-01-05 06:53:39" }
181	];
182	
183	// 对应图表中的静态身体成分数据
184	const rawBody = [
185	    {"date": "2025-11-03", "w": 82.6, "f": 28.7}, {"date": "2025-11-14", "w": 79.7, "f": 26.2},
186	    {"date": "2025-11-18", "w": 79.3, "f": 25.2}, {"date": "2025-11-20", "w": 79.1, "f": 23.5},
187	    {"date": "2025-12-03", "w": 78.7, "f": 24.3}, {"date": "2025-12-10", "w": 76.5, "f": 22.2},
188	    {"date": "2025-12-23", "w": 76.9, "f": 20.2}, {"date": "2026-01-05", "w": 76.8, "f": 20.6},
189	    {"date": "2026-01-13", "w": 75.9, "f": 22.9}, {"date": "2026-01-20", "w": 75.6, "f": 21.1},
190	    {"date": "2026-01-28", "w": 75.6, "f": 23.2}, {"date": "2026-05-19", "w": 77.0, "f": 21.6}
191	];
192	
193	// --- ⚡ 数据解析引擎逻辑开始 ---
194	// 1. 自动映射填充图表数据
195	rawBody.forEach(d => { const idx = timeline.indexOf(d.date); if(idx!==-1){ weightData[idx]=d.w; fatData[idx]=d.f; } });
196	rawRunningList.forEach(d => {
197	    const shortDate = d.datetime.split(' ')[0]; // 提取 YYYY-MM-DD
198	    const idx = timeline.indexOf(shortDate);
199	    if(idx !== -1) {
200	        distanceData[idx] = d.km;
201	        hrData[idx] = d.bpm;
202	    }
203	});
204	
205	// 2. ⚡ 动态流式渲染 HTML 列表
206	const listContainer = document.getElementById('activityListBody');
207	let listHtml = '';
208	rawRunningList.forEach(item => {
209	    const dateParts = item.datetime.split(' '); // 分割日期与具体时间
210	    listHtml += `
211	        <tr>
212	            <td class="text-left run-title">${item.name}</td>
213	            <td class="text-right km-val">${item.km.toFixed(2)}</td>
214	            <td class="text-right">${item.pace}</td>
215	            <td class="text-right">${item.bpm}</td>
216	            <td class="text-right">${item.time}</td>
217	            <td class="text-right">${dateParts[0]}<span class="time-secondary">${dateParts[1].substring(0,5)}</span></td>
218	        </tr>
219	    `;
220	});
221	listContainer.innerHTML = listHtml;
222	// --- 数据解析逻辑结束 ---
223	
224	// --- 📊 Chart.js 初始化配置 (保持前面的极简标准配置) ---
225	const commonScalesX = { grid: { display: false }, ticks: { color: '#a0aab0', font: { size: 10, weight: 300 }, maxTicksLimit: 8, maxRotation: 0 }, border: { display: false } };
226	
227	const chartBody = new Chart(document.getElementById('bodyChart').getContext('2d'), {
228	    type: 'line',
229	    data: {
230	        labels: timeline,
231	        datasets: [
232	            { label: '体重', data: weightData, borderColor: '#5c768d', backgroundColor: 'transparent', borderWidth: 2, pointRadius: 1.5, spanGaps: true, tension: 0.4, yAxisID: 'yW' },
233	            { label: '体脂率', data: fatData, borderColor: '#c4a475', backgroundColor: 'transparent', borderWidth: 2, pointRadius: 1.5, spanGaps: true, tension: 0.4, yAxisID: 'yF' }
234	        ]
235	    },
236	    options: {
237	        responsive: true, maintainAspectRatio: false,
238	        plugins: { legend: { position: 'top', align: 'end', labels: { boxWidth: 6, usePointStyle: true, font: { size: 11 } } } },
239	        scales: {
240	            x: { ...commonScalesX, ticks: { display: false } },
241	            yW: { type: 'linear', position: 'left', min: 70, max: 85, ticks: { color: '#a0aab0', font: { size: 10 }, stepSize: 5, callback: v => v+' kg' }, grid: { color: '#f2eee9' }, border: { display: false } },
242	            yF: { type: 'linear', position: 'right', min: 15, max: 35, ticks: { color: '#a0aab0', font: { size: 10 }, stepSize: 5, callback: v => v+' %' }, grid: { display: false }, border: { display: false } }
243	        }
244	    }
245	});
246	
247	const chartRunning = new Chart(document.getElementById('runningChart').getContext('2d'), {
248	    data: {
249	        labels: timeline,
250	        datasets: [
251	            { type: 'bar', label: '跑步距离', data: distanceData, backgroundColor: 'rgba(92, 118, 141, 0.4)', hoverBackgroundColor: 'rgba(92, 118, 141, 0.7)', barThickness: 6, yAxisID: 'yDistance' },
252	            { type: 'line', label: '平均心率', data: hrData, borderColor: '#db8a75', backgroundColor: 'transparent', borderWidth: 2, pointRadius: 1.5, spanGaps: true, tension: 0.4, yAxisID: 'yH' }
253	        ]
254	    },
255	    options: {
256	        responsive: true, maintainAspectRatio: false,
257	        plugins: { legend: { position: 'top', align: 'end', labels: { boxWidth: 6, usePointStyle: true, font: { size: 11 } } }, tooltip: { usePointStyle: true } },
258	        scales: {
259	            x: commonScalesX,
260	            yDistance: { type: 'linear', position: 'left', min: 0, max: 20, ticks: { color: '#a0aab0', font: { size: 10 }, stepSize: 5, callback: v => v+' km' }, grid: { color: '#f2eee9' }, border: { display: false } },
261	            yH: { type: 'linear', position: 'right', min: 110, max: 160, ticks: { color: '#a0aab0', font: { size: 10 }, stepSize: 10, callback: v => v+' bpm' }, grid: { display: false }, border: { display: false } }
262	        }
263	    }
264	});
265	
266	// 鼠标悬停多图表垂直十字联动
267	function triggerHover(targetChart, event) {
268	    const points = targetChart.getElementsAtEventForMode(event, 'index', { intersect: false }, true);
269	    if (points.length > 0) { targetChart.setActiveElements(points); targetChart.tooltip.setActiveElements(points, { x: event.x, y: event.y }); targetChart.update('none'); }
270	}
271	document.getElementById('bodyChart').addEventListener('mousemove', (e) => { triggerHover(chartRunning, chartBody.helpers.getRelativePosition(e, chartBody)); });
272	document.getElementById('runningChart').addEventListener('mousemove', (e) => { triggerHover(chartBody, chartRunning.helpers.getRelativePosition(e, chartRunning)); });
273	</script>
