1	const fs = require('fs-extra'); // 如果没安装可以 npm i fs-extra，或者用原生的 fs
2	const hljs = require('highlight.js'); // 确保这一行存在且在 markdown-it 配置之前
3	const taskLists = require('markdown-it-task-lists');
4	const path = require('path');
5	const matter = require('gray-matter');
6	
7	const md = require('markdown-it')({
8	    hhtml: true,       // 允许 MD 中的 HTML
9	    linkify: true,    // 自动转换链接
10	    typographer: true, // 启用一些排版优化
11	    highlight: function (str, lang) {
12	        if (lang && hljs.getLanguage(lang)) {
13	            try {
14	                // 注意这里：必须外层包裹 hljs 类名
15	                return '<pre class="hljs"><code>' +
16	                       hljs.highlight(str, { language: lang, ignoreIllegals: true }).value +
17	                       '</code></pre>';
18	            } catch (__) {}
19	        }
20	        return '<pre class="hljs"><code>' + md.utils.escapeHtml(str) + '</code></pre>';
21	    }
22	}).use(taskLists, { label: true });
23	const ejs = require('ejs');
24	
25	// 配置路径
26	const POSTS_DIR = path.join(__dirname, 'posts');
27	const DIST_DIR = path.join(__dirname, 'dist');
28	const THEME_DIR = path.join(__dirname, 'theme');
29	
30	// 1. 清理并准备输出目录
31	if (fs.existsSync(DIST_DIR)) fs.rmSync(DIST_DIR, { recursive: true });
32	fs.mkdirSync(DIST_DIR);
33	
34	// 2. 拷贝 CSS 和静态资源
35	fs.copyFileSync(path.join(THEME_DIR, 'style.css'), path.join(DIST_DIR, 'style.css'));
36	
37	// 拷贝 assets 目录到 dist
38	if (fs.existsSync(path.join(__dirname, 'assets'))) {
39	    fs.copySync(path.join(__dirname, 'assets'), path.join(DIST_DIR, 'assets'));
40	}
41	
42	// 3. 读取所有文章
43	const files = fs.readdirSync(POSTS_DIR).filter(f => f.endsWith('.md'));
44	
45	const postList = [];
46	const allTags = {}; // tag -> [{title, url, date}]
47	
48	// Extract inline #hashtags from markdown content, excluding code blocks, headings, etc.
49	function extractInlineTags(content) {
50	    const tags = new Set();
51	    // Remove code blocks (fenced and inline) to avoid false positives
52	    const cleaned = content
53	        .replace(/```[\s\S]*?```/g, '')
54	        .replace(/`[^`]*`/g, '')
55	        .replace(/^#{1,6}\s+.*/gm, ''); // Remove markdown headings
56	    // Match #tag patterns: # followed by CJK or alphanumeric chars
57	    const tagRegex = /(?:^|\s)#([\w一-鿿぀-ゟ゠-ヿ]+)/g;
58	    let match;
59	    while ((match = tagRegex.exec(cleaned)) !== null) {
60	        tags.add(match[1]);
61	    }
62	    return Array.from(tags);
63	}
64	
65	// Replace inline #tag with styled links in rendered HTML
66	function replaceInlineTags(html, tags) {
67	    tags.forEach(tag => {
68	        // Match #tag that is NOT inside <code>, <pre>, or already inside an HTML tag
69	        // Use a simple approach: replace #tag that appears as text content
70	        const escapedTag = tag.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
71	        const regex = new RegExp('(?<![\\w/])#' + escapedTag + '(?![\\w])', 'g');
72	        html = html.replace(regex, '<a href="#" class="inline-tag" data-tag="' + tag + '">#' + tag + '</a>');
73	    });
74	    return html;
75	}
76	
77	// 1. 循环处理每一篇文章
78	files.forEach(file => {
79	    const rawContent = fs.readFileSync(path.join(POSTS_DIR, file), 'utf-8');
80	    const { data, content } = matter(rawContent);
81	    // 修正图片路径：将 ../assets/ 替换为 ./assets/
82	    const fixedContent = content.replace(/\.\.\/assets\//g, './assets/');
83	
84	    // Extract tags from frontmatter and inline
85	    const frontmatterTags = (data.tags || []).map(t => String(t));
86	    const inlineTags = extractInlineTags(fixedContent);
87	    const mergedTags = [...new Set([...frontmatterTags, ...inlineTags])];
88	
89	    // Render markdown first, then replace inline #tags with links
90	    let htmlContent = md.render(fixedContent);
91	    htmlContent = replaceInlineTags(htmlContent, inlineTags);
92	
93	    // 日期处理逻辑
94	    const postDate = data.date ? new Date(data.date) : new Date(0);
95	    const isValidDate = !isNaN(postDate.getTime());
96	
97	    const postData = {
98	        title: data.title || '无题',
99	        subtitle: data.subtitle || '',
100	        date: isValidDate ? postDate.toISOString().split('T')[0] : '未知日期',
101	        rawDate: postDate,
102	        url: file.replace('.md', '.html'),
103	        content: htmlContent,
104	        tags: mergedTags,
105	        categories: data.categories || []
106	    };
107	
108	    // Build tag index
109	    mergedTags.forEach(tag => {
110	        if (!allTags[tag]) allTags[tag] = [];
111	        allTags[tag].push({ title: postData.title, url: postData.url, date: postData.date });
112	    });
113	
114	    postList.push(postData);
115	});
116	
117	// 2. Render post detail pages (after tag index is built)
118	postList.forEach(postData => {
119	    const postHtml = ejs.render(fs.readFileSync(path.join(THEME_DIR, 'layout.ejs'), 'utf-8'), {
120	        ...postData,
121	        tagIndex: JSON.stringify(allTags)
122	    });
123	    fs.writeFileSync(path.join(DIST_DIR, postData.url), postHtml);
124	});
125	
126	// 2. 首页渲染（在循环结束后执行一次）
127	// 按时间倒序
128	postList.sort((a, b) => b.rawDate - a.rawDate);
129	
130	// 读取 token 用量数据（直接从 .data TSV 文件聚合）
131	let tokenUsageData = { days: [] };
132	const TOKEN_USAGE_DIR = path.join(__dirname, 'token-usage');
133	if (fs.existsSync(TOKEN_USAGE_DIR)) {
134	    const dayMap = {};
135	    const dataFiles = fs.readdirSync(TOKEN_USAGE_DIR).filter(f => /^\d{4}-\d{2}-\d{2}(_.+)?\.data$/.test(f)).sort();
136	    for (const df of dataFiles) {
137	        const date = df.replace(/_.+$/, '').replace(/\.data$/, ''); // Extract YYYY-MM-DD
138	        const lines = fs.readFileSync(path.join(TOKEN_USAGE_DIR, df), 'utf-8').trim().split('\n');
